import { useState } from "react";
import { motion } from "framer-motion";
import SEOHead from "@/components/SEOHead";
import AdPlaceholder from "@/components/AdPlaceholder";
import RelatedTools from "@/components/RelatedTools";
import ShareButton from "@/components/ShareButton";
import SliderInput from "@/components/SliderInput";
import FAQItem from "@/components/FAQItem";
import FreelanceExpandedContent, { FREELANCE_EXPANDED_FAQS } from "@/components/FreelanceExpandedContent";
import { formatCurrencyValue, useCurrencyVersion } from "@/lib/currency";

function fmt(n: number) {
  return formatCurrencyValue(n, { maximumFractionDigits: 2 });
}
function fmt0(n: number) {
  return formatCurrencyValue(n, { maximumFractionDigits: 0 });
}


const FAQS = [
  { q: "How do I convert monthly salary to hourly rate?", a: "Divide your monthly salary by the average number of working hours in a month. We use 4.33 weeks per month (52 weeks  x  12). So: Hourly Rate = Monthly Salary  x  (Weekly Hours  x  4.33)." },
  { q: "How many working hours are in a month on average?", a: "Approximately 174 hours (40 hrs  x  4.33 weeks). This varies slightly by month - some months have 4 weeks and others nearly 5. Using 4.33 gives an accurate annual average." },
  { q: "Why would I want to know my salary as an hourly rate?", a: "It helps you compare job offers, evaluate freelance opportunities, and understand your true earnings per hour after benefits and taxes. It also helps if you're transitioning from employment to freelancing." },
  { q: "Does the converter account for taxes or benefits?", a: "No - this shows your gross hourly rate. To get your take-home rate, subtract taxes (typically 20-35%) and account for employer benefits (health insurance, retirement) that may not carry over to freelance work." },
  { q: "What should my freelance rate be compared to my salary?", a: "The rule of thumb is 3 x  your equivalent employee hourly rate. Freelancers must cover self-employment tax (~15%), health insurance, unpaid time off, and non-billable hours. If your salary is $50/hr equivalent, charge $150/hr as a freelancer." },
  { q: "How do I calculate my hourly rate from an annual salary?", a: "Annual Salary  x  (Weekly Hours  x  52). A $60,000 salary at 40 hrs/week = $60,000  x  2,080 = $28.85/hour. This is your equivalent hourly rate assuming full-time employment." },
  { q: "Is it better to be paid salary or hourly?", a: "Salary provides income stability and often includes benefits (PTO, health insurance, retirement matching). Hourly pay may earn overtime and provides flexibility. For high earners working predictable hours, salary often wins; for variable schedules, hourly may be better." },
];

const EXPANDED_FAQS = FREELANCE_EXPANDED_FAQS.salary;

export default function SalaryToHourlyConverter() {
  useCurrencyVersion();
  const [monthlySalary, setMonthlySalary] = useState(5000);
  const [weeklyHours, setWeeklyHours] = useState(40);
  const hourlyRate = weeklyHours > 0 ? monthlySalary / (weeklyHours * 4.33) : 0;
  const dailyRate = hourlyRate * 8;
  const annualSalary = monthlySalary * 12;
  const freelanceTarget = hourlyRate * 3;

  const salaryRows = [2000, 3000, 4000, 5000, 6000, 8000, 10000, 15000].map(m => ({
    monthly: m,
    hourly: m / (weeklyHours * 4.33),
    annual: m * 12,
  }));

  return (
    <>
      <SEOHead
        title="Free Salary to Hourly Calculator Online - Convert Instantly | CalcHive"
        description="Free online salary to hourly calculator. Instantly convert your monthly or annual salary into hourly, daily and weekly rates. 100% free, works for everyone, no signup needed."
        canonical="/salary-to-hourly-converter"
        keywords="free salary to hourly calculator, salary to hourly converter free online, convert salary to hourly free, monthly salary calculator free"
        category="Freelance"
        faqs={EXPANDED_FAQS}
      />
      <main className="max-w-3xl mx-auto px-4 sm:px-6 py-10">
        <div className="mb-8">
          <span className="inline-flex items-center gap-1.5 text-xs font-semibold uppercase tracking-widest text-primary bg-accent px-3 py-1 rounded-full mb-4">Freelance</span>
          <h1 className="text-3xl sm:text-4xl font-extrabold text-foreground tracking-tight mb-3">Free Salary to Hourly Calculator Online</h1>
          <p className="text-muted-foreground leading-relaxed">Use this free salary to hourly calculator to convert any monthly salary into an equivalent hourly rate. It is useful when comparing job offers, evaluating consulting opportunities, or calculating your minimum freelance rate when transitioning from employment.</p>
        </div>
        <AdPlaceholder size="banner" className="mb-8" />
        <section className="bg-card border border-border rounded-2xl p-6 sm:p-8 shadow-md mb-8">
          <div className="space-y-6 mb-8">
            <SliderInput id="monthly-salary" label="Monthly Salary" value={monthlySalary} min={500} max={50000} step={100} onChange={setMonthlySalary} format={fmt} testId="input-monthly-salary" />
            <SliderInput id="weekly-hours-s" label="Weekly Working Hours" value={weeklyHours} min={1} max={80} step={1} onChange={setWeeklyHours} testId="input-weekly-hours" helpText="hours/week" />
          </div>
          <motion.div key={`${monthlySalary}-${weeklyHours}`} initial={{ opacity: 0.7, y: 4 }} animate={{ opacity: 1, y: 0 }} transition={{ duration: 0.25 }}>
            <div className="bg-gradient-to-br from-primary to-indigo-700 rounded-2xl p-6 mb-4 text-center shadow-lg">
              <p className="text-xs font-semibold uppercase tracking-widest text-primary-foreground/70 mb-1">Hourly Rate</p>
              <p className="text-6xl font-black text-white tracking-tight" data-testid="result-hourly">{fmt(hourlyRate)}</p>
              <p className="text-primary-foreground/70 text-sm mt-1">per hour</p>
            </div>
            <div className="grid grid-cols-3 gap-3 mb-3">
              {[
                { label: "Daily Rate (8 hrs)", value: fmt(dailyRate), testId: "result-daily" },
                { label: "Monthly", value: fmt(monthlySalary) },
                { label: "Annual", value: fmt0(annualSalary), testId: "result-annual" },
              ].map(({ label, value, testId }) => (
                <div key={label} className="bg-accent/60 border border-border rounded-xl p-4 text-center hover:shadow-sm transition-shadow">
                  <p className="text-xs text-muted-foreground font-medium mb-1">{label}</p>
                  <p className="text-lg font-extrabold text-foreground" data-testid={testId}>{value}</p>
                </div>
              ))}
            </div>
            <div className="bg-amber-50 dark:bg-amber-950/20 border border-amber-200 dark:border-amber-800 rounded-xl p-4 text-sm text-amber-700 dark:text-amber-400">
              Recommended freelance rate (3 x  rule): <strong>{fmt(freelanceTarget)}/hour</strong> - accounts for taxes, benefits gap, and non-billable time
            </div>
          </motion.div>
        </section>
        <ShareButton />

        <section className="mb-8 space-y-6">
          <h2 className="text-2xl font-bold text-foreground">How to Convert Your Salary to Hourly Rate for Free</h2>
          <p className="text-muted-foreground leading-relaxed">Monthly salary is converted to hourly rate using the average number of working hours per month. Use this salary to hourly converter free online to convert salary to hourly free with the annual average of 4.33 weeks per month.</p>
          <div className="bg-accent/60 border border-border rounded-2xl p-5 font-mono text-sm text-foreground space-y-1">
            <p>Monthly Hours = Weekly Hours  x  4.33</p>
            <p>Hourly Rate = Monthly Salary  x  Monthly Hours</p>
            <p>Annual Salary = Monthly Salary  x  12</p>
            <p className="text-xs text-muted-foreground mt-2">Freelance target = Hourly Rate  x  3 (3 x  multiplier for self-employment overhead)</p>
          </div>

          <h2 className="text-2xl font-bold text-foreground">Monthly Salary to Hourly Rate - Instant Free Conversion</h2>
          <div className="overflow-x-auto">
            <table className="w-full text-sm border border-border rounded-xl overflow-hidden">
              <thead className="bg-muted/60">
                <tr>
                  {["Monthly Salary", "Hourly Rate", "Annual Salary", "Freelance Rate (3 x )"].map(h => <th key={h} className="text-left py-3 px-4 font-semibold text-foreground">{h}</th>)}
                </tr>
              </thead>
              <tbody className="divide-y divide-border">
                {salaryRows.map(({ monthly, hourly, annual }) => (
                  <tr key={monthly} className={`hover:bg-muted/30 ${monthly === monthlySalary ? "bg-primary/5 font-semibold" : ""}`}>
                    <td className="py-2.5 px-4 font-semibold text-foreground">{fmt(monthly)}/mo</td>
                    <td className="py-2.5 px-4 text-primary font-medium">{fmt(hourly)}/hr</td>
                    <td className="py-2.5 px-4 text-muted-foreground">{fmt0(annual)}/yr</td>
                    <td className="py-2.5 px-4 text-amber-600 dark:text-amber-400">{fmt(hourly * 3)}/hr</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
          <h2 className="text-2xl font-bold text-foreground">Free Salary Calculator for Employees and Job Seekers</h2>
          <p className="text-muted-foreground leading-relaxed">This monthly salary calculator free helps employees, job seekers, and freelancers compare monthly, annual, daily, and hourly pay before making a career or pricing decision.</p>
        </section>

        <FreelanceExpandedContent kind="salary" />

        <section className="mb-8">
          <h2 className="text-xl font-bold text-foreground mb-4">Frequently Asked Questions</h2>
          <div className="space-y-3">{EXPANDED_FAQS.map(f => <FAQItem key={f.q} q={f.q} a={f.a} />)}</div>
        </section>
        <AdPlaceholder size="rectangle" className="mx-auto mb-8" />
        <RelatedTools exclude="/salary-to-hourly-converter" headingLevel="h3" />
      </main>
    </>
  );
}


